import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"哪里买？","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/电脑/哪里买.md","filePath":"ccc/电脑/哪里买.md"}`),a={name:`ccc/电脑/哪里买.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="哪里买" tabindex="-1">哪里买？ <a class="header-anchor" href="#哪里买" aria-label="Permalink to “哪里买？”">​</a></h1><p>2021.3.26</p><h2 id="整机-淘宝装机最大的问题" tabindex="-1">整机，淘宝装机最大的问题 <a class="header-anchor" href="#整机-淘宝装机最大的问题" aria-label="Permalink to “整机，淘宝装机最大的问题”">​</a></h2><p>代理在找厂家进货的时候都一定要搭售一大堆卖不出去的辣鸡。</p><p>网红型号根本不愁卖。整机，装机用的配件都是大牌子在diy市场根本卖不出的辣鸡。如果没有整机，淘宝装机，基本上亏本贱卖都卖不出去。</p><p>超级小桀的整机，有华硕中国总经理tony站台，对接华硕一级代理，档位够高了吧，照样安排一水的辣鸡，这就是整机市场的天道，做整机生意不卖辣鸡根本无法生存。<a href="https://store.taobao.com/shop/view_shop.htm?appUid=RAzN8HWQKzHdAzjqX1FYoGiCZsWWTzkVXxfuCa7uVHKJuoTfzcH" target="_blank" rel="noreferrer">尘雨科技</a>的玄武电源，把利润砍掉一大半，其他品牌干脆直接不准代工厂给他代工。</p><p>整机并非完全一无是处，默频使用，当成普通的消费电子产品，两三年一换，也都是可以正常使用的。</p><p>非要买整机，可以看看这三家：</p><p>中正评测，经典整机路数，跟武汉三雄一个德性，但至少比友商便宜。支持自定义配件装机。</p><p><a href="https://item.taobao.com/item.htm?spm=a1z10.5-c-s.w4002-23381477500.20.303b2d87rNkaPP&amp;id=634856101716" target="_blank" rel="noreferrer">淘宝摩西电脑</a> 在整机里相对正常一点，但是也贵。</p><p><a href="https://item.taobao.com/item.htm?spm=a1z10.3-c-s.w4002-22612454453.25.69c578b5iYg286&amp;id=591304315363" target="_blank" rel="noreferrer">装机猿合作·淘宝西安水元素</a> 正常程度比摩西差，但是便宜。</p><p>支持自定义配件装机的，可以自己在公众号-游推社，图拉丁吧等社群找配置单。</p><h3 id="品牌机" tabindex="-1">品牌机 <a class="header-anchor" href="#品牌机" aria-label="Permalink to “品牌机”">​</a></h3><p>板卡非常非常丐，几乎没有升级余量，但是省心，有售后，有客服。</p><h3 id="自选配件自行装机" tabindex="-1">自选配件自行装机 <a class="header-anchor" href="#自选配件自行装机" aria-label="Permalink to “自选配件自行装机”">​</a></h3><p>装机教程视频推荐：</p><p><a href="https://www.bilibili.com/video/BV1BG4y137mG" target="_blank" rel="noreferrer">全网最好的装机教程</a></p><p><a href="https://space.bilibili.com/35359510/video?keyword=%E8%A3%85%E6%9C%BA%E6%95%99%E7%A8%8B" target="_blank" rel="noreferrer">远古时代装机猿的装机教程</a></p><blockquote><p>优点：整机档次的配件，价格更便宜。整机的价格，用料更好，超频潜力，升级潜力更强。</p><p>缺点：麻烦，折腾。京东自营买配件性价比不如整机。要淘宝闲鱼拼多多折腾拉满。</p></blockquote><h3 id="花装机服务费" tabindex="-1">花装机服务费 <a class="header-anchor" href="#花装机服务费" aria-label="Permalink to “花装机服务费”">​</a></h3><p>网购配件，<a href="https://item.jd.com/4939617.html#crumb-wrap" target="_blank" rel="noreferrer">京东148块上门装机</a>或附近电脑店，电脑店有可能掉包。</p><h3 id="整机" tabindex="-1">整机 <a class="header-anchor" href="#整机" aria-label="Permalink to “整机”">​</a></h3><blockquote><p>警惕洋垃圾，特点是i7级，i9级，xx级类似这样的字眼，cpu以e5,e3为主，显卡矿卡。稳定性很差，除非开工作室多开。</p></blockquote><p>普遍用料差，配件特供，寿命期望短，没有升级余量，超频余量，售后费劲。规模较大的店：武极，京天华盛，攀升。</p><blockquote><p><strong>整机是板卡返修良品的主要出货渠道。固态硬盘是白片黑片的主要出货渠道。内存也是白片黑片拆机片的主要出货渠道，不过内存能点亮一般没事，无非不能超频。</strong></p><p>主板显卡本来就有“网吧专供”，基于零售型号阉割。缩供电，接口，RGB。型号通常加后缀，甚至有不改的，看BIOS才能看出来。这种主板实体店也会用。整机板卡还要进一步阉割供电和接口，用档次更低的接插件。</p></blockquote><blockquote><p>现代cpu和显卡，都有非常高的瞬时功耗，整机的缩水电源很容易顶不住。市网电压稍微有点波动，整机就容易掉电。</p></blockquote><h3 id="实体店" tabindex="-1">实体店 <a class="header-anchor" href="#实体店" aria-label="Permalink to “实体店”">​</a></h3><p>网上有价保，实体店进货更便宜，偏爱高利润配件，看人下菜。</p><h2 id="网购配件哪买" tabindex="-1">网购配件哪买？ <a class="header-anchor" href="#网购配件哪买" aria-label="Permalink to “网购配件哪买？”">​</a></h2><p>B站有很多日更搜罗优惠信息的，可以作为价格参考。</p><h3 id="cpu" tabindex="-1">cpu <a class="header-anchor" href="#cpu" aria-label="Permalink to “cpu”">​</a></h3><p>通常很少坏，找便宜的，闲鱼，淘宝。</p><p>魔改,ES最好淘宝，好赖有店铺。魔改普遍稳定的不便宜，便宜的稳定性堪忧。而且卖二手的时候残值率低，我是觉得完全没有折腾的意义。</p><h3 id="主板" tabindex="-1">主板 <a class="header-anchor" href="#主板" aria-label="Permalink to “主板”">​</a></h3><p>京东自营蹲活动。</p><ul><li><p>主板故障率相对最高，京东售后舒服。那几个出货量大的板u套商家，售后主板有得等了。</p></li><li><p>所有第三方商家的板u套都会混发良品和退货。</p></li><li><p>自营活动价加散片CPU，同板U套价格相近。</p></li><li><p>老主板不推荐二手，修过或电气性能衰减。不如考虑华南金牌，精粤等翻新，七彩虹映泰梅捷昂达等二三线，至少有售后。</p></li></ul><h3 id="显卡" tabindex="-1">显卡 <a class="header-anchor" href="#显卡" aria-label="Permalink to “显卡”">​</a></h3><p><strong>以下品牌溢价少，性价比合理。</strong></p><ul><li>铭瑄电竞之心，翔升。支持个人送保，一般柏能代工，返修率最低。</li><li>同德丐卡推荐在影驰，耕升，铭瑄，盈通里找最便宜的，懒得找推荐耕升，品牌溢价低，而且基本就是同德公版丐，不会再缩水。</li><li>电竞判客，栢能系（索泰，映众）最便宜。</li><li>以上品牌的丐卡一般代理商送保居多，京东买售后方便。</li><li>京东自营可以考虑PNY，比亚迪代工。</li></ul><p>性价比低：索泰霹雳毁灭，七彩虹元气，战斧，网驰。</p><p>台湾品牌仗着品牌溢价，又贵又丐，甚至为了打价格战，低端系列大量启用矿卡作坊代工。</p><h3 id="非公" tabindex="-1">非公 <a class="header-anchor" href="#非公" aria-label="Permalink to “非公”">​</a></h3><ul><li>二线非公差价很小才考虑，大都不提升供电，就换个三风扇散热器，甚至往往是负作用。</li></ul><blockquote><p>索泰PGF，天启；七彩虹adoc；影驰星曜；微星魔龙；华硕ROG，KO等非公会升级供电，但是性价比很低。</p></blockquote><ul><li>是否要非公建议看供电相数，drmos每相效率高，温度低的甜蜜点在30w左右。</li></ul><p>xx70及以上卡，丐卡都给到10相以上，供电完全足够，非公堆供电，反而增大故障率期望。</p>`,46)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};